from dataclasses import dataclass, field
from typing import Callable, Optional
from enum import Enum

class ScorerType(str, Enum):
    LLM_JUDGE   = "llm_judge"
    REGEX       = "regex"
    HUMAN_SAMPLE = "human_sample"
    EMBEDDING   = "embedding_similarity"

@dataclass
class EvalCase:
    case_id: str
    input: str              # user query or prompt
    expected: str           # ground-truth reference answer
    context: Optional[str] = None   # retrieved documents for RAG evals

@dataclass
class SuccessCriterion:
    name: str
    description: str
    quality_bar: float          # the threshold (e.g. 0.02 for ≤ 2% hallucination)
    direction: str              # "lower_better" or "higher_better"
    scorer_type: ScorerType
    eval_set_size: int
    owner: str
    ci_blocking: bool = True    # if True, failing this gate blocks deployment

    def passes(self, score: float) -> bool:
        if self.direction == "lower_better":
            return score <= self.quality_bar
        return score >= self.quality_bar

@dataclass
class EvalResult:
    criterion: SuccessCriterion
    score: float
    failing_cases: list[str]    # case_ids that failed
    run_id: str

    @property
    def passed(self) -> bool:
        return self.criterion.passes(self.score)

    def summary(self) -> str:
        status = "PASS" if self.passed else "FAIL"
        return (
            f"[{status}] {self.criterion.name}: "
            f"score={self.score:.4f} "
            f"(bar={self.criterion.quality_bar}, {self.criterion.direction})"
        )

# Eval set composition rules for a production GenAI feature
# (FNOL chatbot example — 100 cases)

EVAL_SET_COMPOSITION = {
    # Core capability: the thing the AI is designed to do
    "core_intent_coverage": {
        "fraction": 0.40,
        "cases": 40,
        "description": "Representative FNOL queries across claim types (vehicle, property, health)",
        "labelling": "Human expert labels expected answer and cites source",
    },

    # Edge cases: unusual but valid inputs
    "edge_cases": {
        "fraction": 0.20,
        "cases": 20,
        "description": "Ambiguous claims, partial information, multi-step queries",
        "labelling": "Human expert labels + notes why the case is hard",
    },

    # Adversarial / safety probes
    "adversarial": {
        "fraction": 0.15,
        "cases": 15,
        "description": "Prompt injection attempts, out-of-scope requests, PII fishing",
        "labelling": "Expected: refusal or redirection; any other output is a failure",
    },

    # Regression cases from past production failures
    "regression": {
        "fraction": 0.15,
        "cases": 15,
        "description": "Interactions that produced wrong outputs in previous runs",
        "labelling": "Corrected output labelled by AI quality team",
    },

    # Fairness probes
    "fairness_probes": {
        "fraction": 0.10,
        "cases": 10,
        "description": "Identical queries with varied claimant names / locations",
        "labelling": "Expected: identical outputs regardless of demographic signal",
    },
}

# Regression guard: track quality bar score over time

import json
from pathlib import Path

HISTORY_FILE = Path(".eval_history.json")

def record_run(run_id: str, results: list[EvalResult]) -> None:
    history = json.loads(HISTORY_FILE.read_text()) if HISTORY_FILE.exists() else []
    history.append({
        "run_id": run_id,
        "results": [
            {
                "criterion": r.criterion.name,
                "score": r.score,
                "passed": r.passed,
                "failing_cases": r.failing_cases,
            }
            for r in results
        ],
    })
    HISTORY_FILE.write_text(json.dumps(history, indent=2))

def detect_regression(criterion_name: str, n_runs: int = 5) -> bool:
    """
    Returns True if the last n_runs show a monotonically worsening trend
    for the given criterion. Catches slow-burn quality decay.
    """
    history = json.loads(HISTORY_FILE.read_text())
    scores = [
        run["results"][i]["score"]
        for run in history[-n_runs:]
        for i, r in enumerate(run["results"])
        if r["criterion"] == criterion_name
    ]
    if len(scores) < n_runs:
        return False
    return all(scores[i] < scores[i+1] for i in range(len(scores)-1))
    # "lower is better" interpretation — flip sign for higher_better criteria
